import json, requests, re
from pathlib import Path

PAGE_ID='1a184951-e962-8038-a147-e99f49b82bd1'
NOTION_API='https://www.notion.so/api/v3'
TIMEOUT=30


def post(path,payload):
    r=requests.post(f'{NOTION_API}/{path}',json=payload,timeout=TIMEOUT)
    r.raise_for_status()
    return r.json()

def fetch_chunk(pid):
    data=post('loadCachedPageChunk',{
        'pageId':pid,
        'limit':100,
        'cursor':{'stack':[]},
        'chunkNumber':0,
        'verticalColumns':False,
    })
    return data.get('recordMap',{}).get('block',{}) or {}

def sync(ids):
    if not ids:
        return {}
    data=post('syncRecordValues',{'requests':[{'id':i,'table':'block','version':-1} for i in ids]})
    return data.get('recordMap',{}).get('block',{}) or {}

def bval(entry):
    if not isinstance(entry,dict):
        return {}
    v=entry.get('value')
    if isinstance(v,dict) and isinstance(v.get('value'),dict):
        return v['value']
    return v if isinstance(v,dict) else {}

def title_plain(v):
    props=v.get('properties') or {}
    t=props.get('title') or []
    out=[]
    for seg in t:
        if isinstance(seg,list) and seg and isinstance(seg[0],str):
            out.append(seg[0])
    return ''.join(out).strip()

def gather_refs(blocks,root):
    refs=set(); stack=[root]; seen=set()
    while stack:
        bid=stack.pop()
        if bid in seen: continue
        seen.add(bid); refs.add(bid)
        v=bval(blocks.get(bid,{}))
        for c in v.get('content') or []:
            if isinstance(c,str): stack.append(c)
    return refs

blocks=fetch_chunk(PAGE_ID)
for _ in range(30):
    refs=gather_refs(blocks,PAGE_ID)
    missing=[x for x in refs if x not in blocks]
    if not missing:
        break
    before=len(blocks)
    for i in range(0,len(missing),100):
        got=sync(missing[i:i+100])
        for k,e in got.items():
            if k not in blocks and bval(e):
                blocks[k]=e
    if len(blocks)==before:
        break

rootv=bval(blocks.get(PAGE_ID,{}))
print('title=',title_plain(rootv))
print('blocks=',len(blocks))

imgs=[]
for bid,entry in blocks.items():
    v=bval(entry)
    t=v.get('type')
    if t=='image':
        fmt=v.get('format') or {}
        props=v.get('properties') or {}
        url=fmt.get('display_source') or fmt.get('source')
        if not url:
            for key in ('source','link','url'):
                p=props.get(key)
                if p and isinstance(p,list) and p and isinstance(p[0],list) and p[0] and isinstance(p[0][0],str):
                    url=p[0][0]; break
        cap=''
        c=props.get('caption') or []
        for seg in c:
            if isinstance(seg,list) and seg and isinstance(seg[0],str):
                cap+=seg[0]
        imgs.append((bid,url,cap))
print('images=',len(imgs))
for i,(bid,url,cap) in enumerate(imgs[:20],1):
    print(i,bid,url[:120] if isinstance(url,str) else url,cap)

out=Path('D:/paper_reading/paper_reading/notes/_notion_raw')
out.mkdir(parents=True,exist_ok=True)
raw=out/'Maintaining Plasticity in Deep Continual Learning.json'
raw.write_text(json.dumps({'title':title_plain(rootv),'page_id':PAGE_ID,'blocks':blocks},ensure_ascii=False,indent=2),encoding='utf-8')
print('saved',raw)
