import json
from pathlib import Path

p=Path('D:/paper_reading/paper_reading/notes/_notion_raw/Maintaining Plasticity in Deep Continual Learning.json')
obj=json.loads(p.read_text(encoding='utf-8'))
blocks=obj['blocks']
root=obj['page_id']

def bval(entry):
    if not isinstance(entry,dict):
        return {}
    v=entry.get('value')
    if isinstance(v,dict) and isinstance(v.get('value'),dict):
        return v['value']
    return v if isinstance(v,dict) else {}

def rich_plain(parts):
    if not parts:
        return ''
    out=[]
    for seg in parts:
        if isinstance(seg,list) and seg and isinstance(seg[0],str):
            out.append(seg[0])
    return ''.join(out).strip()

def prop_plain(v,key):
    return rich_plain((v.get('properties') or {}).get(key))

def block_title(v):
    return prop_plain(v,'title')

def block_url(v):
    fmt=v.get('format') or {}
    props=v.get('properties') or {}
    for k in ('display_source','source'):
        if isinstance(fmt.get(k),str) and fmt.get(k):
            return fmt[k]
    for k in ('source','link','url'):
        txt=rich_plain(props.get(k))
        if txt:
            return txt
    return ''

def bool_prop(v,key):
    return prop_plain(v,key).lower() in {'yes','true','1','checked','x','已完成','是'}

img_counter=0

def render(bid,visited,indent=0):
    global img_counter
    if bid in visited:
        return []
    visited.add(bid)
    if bid not in blocks:
        return [f"{'  '*indent}- [缺失块] `{bid}`"]
    v=bval(blocks[bid]); t=v.get('type','unknown'); title=block_title(v)
    children=[c for c in (v.get('content') or []) if isinstance(c,str)]
    pre='  '*indent
    lines=[]
    if t=='text':
        if title: lines.append(f'{pre}{title}')
    elif t=='header': lines.append(f'{pre}# {title}')
    elif t=='sub_header': lines.append(f'{pre}## {title}')
    elif t=='sub_sub_header': lines.append(f'{pre}### {title}')
    elif t=='bulleted_list': lines.append(f'{pre}- {title or "[空项]"}')
    elif t=='numbered_list': lines.append(f'{pre}1. {title or "[空项]"}')
    elif t=='to_do': lines.append(f"{pre}- [{'x' if bool_prop(v,'checked') else ' '}] {title or '[空项]'}")
    elif t=='quote': lines.append(f'{pre}> {title}')
    elif t=='callout': lines.append(f'{pre}> [!note] {title}')
    elif t=='divider': lines.append(f'{pre}---')
    elif t in {'code','codepen'}:
        lang=(v.get('format') or {}).get('code_language') or ''
        lines.append(f'{pre}```{lang}')
        if title: lines.append(title)
        lines.append(f'{pre}```')
    elif t in {'image','video','audio','file','pdf','bookmark','embed'}:
        url=block_url(v); caption=prop_plain(v,'caption')
        row=f"{pre}- [{t}] {url or '(无链接)'}"
        if caption: row+=f' | {caption}'
        if t=='image':
            img_counter+=1
            row=f"{row} | image_index={img_counter} | block_id={bid}"
        lines.append(row)
    elif t=='page':
        lines.append(f'{pre}- [子页] {title or bid}')
    elif t=='collection_view_page':
        lines.append(f'{pre}- [数据库视图页] {title or bid}')
    elif t=='table':
        lines.append(f'{pre}- [表格块] {title or bid}')
    else:
        lines.append(f'{pre}- [未专门解析:{t}] {title or "(无标题)"}')

    for cid in children:
        lines.extend(render(cid,visited,indent+1))
    return lines

visited=set()
lines=render(root,visited,0)
out=Path('D:/paper_reading/paper_reading/tmp_maintaining_rendered.md')
out.write_text('\n'.join(lines),encoding='utf-8')
print('saved',out,'lines',len(lines),'images',img_counter)
