import json, urllib.parse, requests
from pathlib import Path

root=Path('D:/paper_reading/paper_reading')
raw_path=root/'notes/_notion_raw/Maintaining Plasticity in Deep Continual Learning.json'
obj=json.loads(raw_path.read_text(encoding='utf-8'))
blocks=obj['blocks']
page_id=obj['page_id']

def bval(e):
    if not isinstance(e,dict):return {}
    v=e.get('value')
    if isinstance(v,dict) and isinstance(v.get('value'),dict):
        return v['value']
    return v if isinstance(v,dict) else {}

def rich_plain(parts):
    out=[]
    for seg in parts or []:
        if isinstance(seg,list) and seg and isinstance(seg[0],str): out.append(seg[0])
    return ''.join(out)

def block_title(v):
    return rich_plain((v.get('properties') or {}).get('title')).strip()

# DFS order
order=[]; seen=set(); stack=[page_id]
while stack:
    bid=stack.pop()
    if bid in seen: continue
    seen.add(bid); order.append(bid)
    v=bval(blocks.get(bid,{}))
